 54→/// JSON file-backed index mapping session key → SessionEntry.
 55→pub struct SessionMetadata {
 56→    path: PathBuf,
 57→    entries: HashMap<String, SessionEntry>,
 58→}
 59→
 60→fn now_ms() -> u64 {
 61→    SystemTime::now()
 62→        .duration_since(UNIX_EPOCH)
 63→        .unwrap_or_default()
 64→        .as_millis() as u64
 65→}
 66→
 67→fn compare_sidebar_order(lhs: &SessionEntry, rhs: &SessionEntry) -> Ordering {
 68→    let lhs_main = lhs.key == "main";
 69→    let rhs_main = rhs.key == "main";
 70→
 71→    rhs_main
 72→        .cmp(&lhs_main)
 73→        .then_with(|| rhs.updated_at.cmp(&lhs.updated_at))
 74→        .then_with(|| rhs.created_at.cmp(&lhs.created_at))
 75→        .then_with(|| lhs.key.cmp(&rhs.key))
 76→}
 77→
 78→impl SessionMetadata {
 79→    /// Load metadata from disk, or create an empty index.
 80→    pub fn load(path: PathBuf) -> Result<Self> {
 81→        let entries = if path.exists() {
 82→            let data = fs::read_to_string(&path)?;
 83→            serde_json::from_str(&data).unwrap_or_default()
 84→        } else {
 85→            HashMap::new()
 86→        };
 87→        Ok(Self { path, entries })
 88→    }
 89→
 90→    /// Persist metadata to disk.
 91→    pub fn save(&self) -> Result<()> {
 92→        if let Some(parent) = self.path.parent() {
 93→            fs::create_dir_all(parent)?;
 94→        }
 95→        let data = serde_json::to_string_pretty(&self.entries)?;
 96→        fs::write(&self.path, data)?;
 97→        Ok(())
 98→    }
 99→
100→    /// Get an entry by key.
101→    pub fn get(&self, key: &str) -> Option<&SessionEntry> {
102→        self.entries.get(key)
103→    }
104→
105→    /// Insert or update an entry. If key doesn't exist, creates a new entry.
106→    pub fn upsert(&mut self, key: &str, label: Option<String>) -> &SessionEntry {
107→        let now = now_ms();
108→        self.entries
109→            .entry(key.to_string())
110→            .and_modify(|e| {
111→                if let Some(ref l) = label
112→                    && e.label.as_deref() != Some(l)
113→                {
114→                    e.label = label.clone();
115→                    e.updated_at = now;
116→                    e.version += 1;
117→                }
118→            })
119→            .or_insert_with(|| SessionEntry {
120→                id: uuid::Uuid::new_v4().to_string(),
121→                key: key.to_string(),
122→                label,
123→                model: None,
124→                created_at: now,
125→                updated_at: now,
126→                message_count: 0,
127→                last_seen_message_count: 0,
128→                project_id: None,
129→                archived: false,
130→                worktree_branch: None,
131→                sandbox_enabled: None,
132→                sandbox_image: None,
133→                channel_binding: None,
134→                parent_session_key: None,
135→                fork_point: None,
136→                mcp_disabled: None,
137→                preview: None,
138→                agent_id: None,
139→                node_id: None,
140→                version: 0,
141→            })
142→    }
143→
144→    /// Update the model associated with a session.
145→    pub fn set_model(&mut self, key: &str, model: Option<String>) {
146→        if let Some(entry) = self.entries.get_mut(key) {
147→            entry.model = model;
148→            entry.updated_at = now_ms();
149→            entry.version += 1;
150→        }

  1→//! Service trait interfaces for domain services.
  2→//!
  3→//! Each trait has a `Noop` implementation that returns empty/default responses,
  4→//! allowing the gateway to run standalone before domain crates are wired in.
  5→
  6→use {async_trait::async_trait, serde_json::Value, tracing::warn};
  7→
  8→/// Error type returned by service methods.
  9→#[derive(Debug, thiserror::Error)]
 10→pub enum ServiceError {
 11→    #[error("{message}")]
 12→    Message { message: String },
 13→    #[error("{message}")]
 14→    Forbidden { message: String },
 15→    #[error("{0}")]
 16→    Serde(#[from] serde_json::Error),
 17→}
 18→
 19→impl ServiceError {
 20→    #[must_use]
 21→    pub fn message(message: impl std::fmt::Display) -> Self {
 22→        Self::Message {
 23→            message: message.to_string(),
 24→        }
 25→    }
 26→
 27→    #[must_use]
 28→    pub fn forbidden(message: impl std::fmt::Display) -> Self {
 29→        Self::Forbidden {
 30→            message: message.to_string(),
 31→        }
 32→    }
 33→}
 34→
 35→impl From<String> for ServiceError {
 36→    fn from(value: String) -> Self {
 37→        Self::message(value)
 38→    }
 39→}
 40→
 41→impl From<&str> for ServiceError {
 42→    fn from(value: &str) -> Self {
 43→        Self::message(value)
 44→    }
 45→}
 46→
 47→impl From<ServiceError> for moltis_protocol::ErrorShape {
 48→    fn from(err: ServiceError) -> Self {
 49→        // INTERNAL is correct here: ServiceError represents application-level failures
 50→        // (validation errors, probe failures, noop-service "not configured" errors).
 51→        // Transient UNAVAILABLE codes are emitted directly by gateway/state.rs,
 52→        // methods/node.rs, and client-side WS checks — they do not flow through
 53→        // ServiceError and are unaffected by this mapping.
 54→        let code = match &err {
 55→            ServiceError::Forbidden { .. } => moltis_protocol::error_codes::FORBIDDEN,
 56→            _ => moltis_protocol::error_codes::INTERNAL,
 57→        };
 58→        Self::new(code, err.to_string())
 59→    }
 60→}
 61→
 62→pub type ServiceResult<T = Value> = Result<T, ServiceError>;
