 59→// ── Location requester ───────────────────────────────────────────────────────
 60→
 61→/// Gateway implementation of [`moltis_tools::location::LocationRequester`].
 62→///
 63→/// Uses the `PendingInvoke` + oneshot pattern to request the user's browser
 64→/// geolocation and waits for `location.result` RPC to resolve it.
 65→struct GatewayLocationRequester {
 66→    state: Arc<GatewayState>,
 67→}
 68→
 69→#[async_trait::async_trait]
 70→impl moltis_tools::location::LocationRequester for GatewayLocationRequester {
 71→    async fn request_location(
 72→        &self,
 73→        conn_id: &str,
 74→        precision: moltis_tools::location::LocationPrecision,
 75→    ) -> moltis_tools::Result<moltis_tools::location::LocationResult> {
 76→        use moltis_tools::location::{LocationError, LocationResult};
 77→
 78→        let request_id = uuid::Uuid::new_v4().to_string();
 79→
 80→        // Send a location.request event to the browser client, including
 81→        // the requested precision so JS can adjust geolocation options.
 82→        let event = moltis_protocol::EventFrame::new(
 83→            "location.request",
 84→            serde_json::json!({ "requestId": request_id, "precision": precision }),
 85→            self.state.next_seq(),
 86→        );
 87→        let event_json = serde_json::to_string(&event)?;
 88→
 89→        {
 90→            let inner = self.state.inner.read().await;
 91→            let clients = &inner.clients;
 92→            let client = clients.get(conn_id).ok_or_else(|| {
 93→                moltis_tools::Error::message(format!("no client connection for conn_id {conn_id}"))
 94→            })?;
 95→            if !client.send(&event_json) {
 96→                return Err(moltis_tools::Error::message(format!(
 97→                    "failed to send location request to client {conn_id}"
 98→                )));
 99→            }
100→        }
101→
102→        // Set up a oneshot for the result with timeout.
103→        let (tx, rx) = tokio::sync::oneshot::channel();
104→        {
105→            let mut inner_w = self.state.inner.write().await;
106→            let invokes = &mut inner_w.pending_invokes;
107→            invokes.insert(request_id.clone(), crate::state::PendingInvoke {
108→                request_id: request_id.clone(),
109→                sender: tx,
110→                created_at: std::time::Instant::now(),
111→            });
112→        }
113→
114→        // Wait up to 30 seconds for the user to grant/deny permission.
115→        let result = match tokio::time::timeout(std::time::Duration::from_secs(30), rx).await {
116→            Ok(Ok(value)) => value,
117→            Ok(Err(_)) => {
118→                // Sender dropped — clean up.
119→                self.state
120→                    .inner
121→                    .write()
122→                    .await
123→                    .pending_invokes
124→                    .remove(&request_id);
125→                return Ok(LocationResult {
126→                    location: None,
127→                    error: Some(LocationError::Timeout),
128→                });
129→            },
130→            Err(_) => {
131→                // Timeout — clean up.
132→                self.state
133→                    .inner
134→                    .write()
135→                    .await
136→                    .pending_invokes
137→                    .remove(&request_id);
138→                return Ok(LocationResult {
139→                    location: None,
140→                    error: Some(LocationError::Timeout),
141→                });
142→            },
143→        };
144→
145→        // Parse the result from the browser.
146→        if let Some(loc) = result.get("location") {
147→            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
148→            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
149→            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
150→            Ok(LocationResult {
151→                location: Some(moltis_tools::location::BrowserLocation {
152→                    latitude: lat,
153→                    longitude: lon,
154→                    accuracy,
155→                }),
156→                error: None,
157→            })
158→        } else if let Some(err) = result.get("error") {
159→            let code = err.get("code").and_then(|v| v.as_u64()).unwrap_or(0);
160→            let error = match code {
161→                1 => LocationError::PermissionDenied,
162→                2 => LocationError::PositionUnavailable,
163→                3 => LocationError::Timeout,
164→                _ => LocationError::NotSupported,
165→            };
166→            Ok(LocationResult {
167→                location: None,
168→                error: Some(error),
169→            })
170→        } else {
171→            Ok(LocationResult {
172→                location: None,
173→                error: Some(LocationError::PositionUnavailable),
174→            })
175→        }
176→    }
