182→    async fn request_channel_location(
183→        &self,
184→        session_key: &str,
185→    ) -> moltis_tools::Result<moltis_tools::location::LocationResult> {
186→        use moltis_tools::location::{LocationError, LocationResult};
187→
188→        // Look up channel binding from session metadata.
189→        let session_meta = self
190→            .state
191→            .services
192→            .session_metadata
193→            .as_ref()
194→            .ok_or_else(|| moltis_tools::Error::message("session metadata not available"))?;
195→        let entry = session_meta.get(session_key).await.ok_or_else(|| {
196→            moltis_tools::Error::message(format!("no session metadata for key {session_key}"))
197→        })?;
198→        let binding_json = entry.channel_binding.ok_or_else(|| {
199→            moltis_tools::Error::message(format!("no channel binding for session {session_key}"))
200→        })?;
201→        let reply_target: moltis_channels::ChannelReplyTarget =
202→            serde_json::from_str(&binding_json)?;
203→
204→        // Send a message asking the user to share their location.
205→        let outbound = self
206→            .state
207→            .services
208→            .channel_outbound_arc()
209→            .ok_or_else(|| moltis_tools::Error::message("no channel outbound available"))?;
210→        outbound
211→            .send_text(
212→                &reply_target.account_id,
213→                &reply_target.outbound_to(),
214→                "Please share your location in this chat, or paste a geo: link / map pin.",
215→                None,
216→            )
217→            .await
218→            .map_err(|e| moltis_tools::Error::external("send location request", e))?;
219→
220→        // Create a pending invoke keyed by session.
221→        let pending_key = format!("channel_location:{session_key}");
222→        let (tx, rx) = tokio::sync::oneshot::channel();
223→        {
224→            let mut inner = self.state.inner.write().await;
225→            inner
226→                .pending_invokes
227→                .insert(pending_key.clone(), crate::state::PendingInvoke {
228→                    request_id: pending_key.clone(),
229→                    sender: tx,
230→                    created_at: std::time::Instant::now(),
231→                });
232→        }
233→
234→        // Wait up to 60 seconds — user needs to navigate Telegram's UI.
235→        let result = match tokio::time::timeout(std::time::Duration::from_secs(60), rx).await {
236→            Ok(Ok(value)) => value,
237→            Ok(Err(_)) => {
238→                self.state
239→                    .inner
240→                    .write()
241→                    .await
242→                    .pending_invokes
243→                    .remove(&pending_key);
244→                return Ok(LocationResult {
245→                    location: None,
246→                    error: Some(LocationError::Timeout),
247→                });
248→            },
249→            Err(_) => {
250→                self.state
251→                    .inner
252→                    .write()
253→                    .await
254→                    .pending_invokes
255→                    .remove(&pending_key);
256→                return Ok(LocationResult {
257→                    location: None,
258→                    error: Some(LocationError::Timeout),
259→                });
260→            },
261→        };
262→
263→        // Parse the result (same format as update_location sends).
264→        if let Some(loc) = result.get("location") {
265→            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
266→            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
267→            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
268→            Ok(LocationResult {
269→                location: Some(moltis_tools::location::BrowserLocation {
270→                    latitude: lat,
271→                    longitude: lon,
272→                    accuracy,
273→                }),
274→                error: None,
275→            })
276→        } else {
277→            Ok(LocationResult {
278→                location: None,
279→                error: Some(LocationError::PositionUnavailable),
280→            })
281→        }
282→    }
283→}
