 28→/// Stdio-based transport for an MCP server process.
 29→pub struct StdioTransport {
 30→    child: Mutex<Child>,
 31→    stdin: Mutex<tokio::process::ChildStdin>,
 32→    pending: Arc<Mutex<HashMap<String, oneshot::Sender<JsonRpcResponse>>>>,
 33→    next_id: AtomicU64,
 34→    request_timeout: Duration,
 35→    /// Handle to the reader task so we can abort on drop.
 36→    reader_handle: Mutex<Option<tokio::task::JoinHandle<()>>>,
 37→}
 38→
 39→impl StdioTransport {
 40→    /// Spawn the server process and start the reader loop.
 41→    pub async fn spawn(
 42→        command: &str,
 43→        args: &[String],
 44→        env: &HashMap<String, String>,
 45→    ) -> Result<Arc<Self>> {
 46→        Self::spawn_with_timeout(command, args, env, Duration::from_secs(30)).await
 47→    }
 48→
 49→    /// Spawn the server process with a custom request timeout and start the reader loop.
 50→    pub async fn spawn_with_timeout(
 51→        command: &str,
 52→        args: &[String],
 53→        env: &HashMap<String, String>,
 54→        request_timeout: Duration,
 55→    ) -> Result<Arc<Self>> {
 56→        info!(
 57→            command = %command,
 58→            args = ?args,
 59→            "spawning MCP server process"
 60→        );
 61→
 62→        let mut cmd = Command::new(command);
 63→        cmd.args(args)
 64→            .envs(env)
 65→            .stdin(Stdio::piped())
 66→            .stdout(Stdio::piped())
 67→            .stderr(Stdio::piped())
 68→            .kill_on_drop(true);
 69→
 70→        let mut child = cmd
 71→            .spawn()
 72→            .with_context(|| format!("failed to spawn MCP server: {command}"))?;
 73→
 74→        let stdin = child.stdin.take().context("failed to capture stdin")?;
 75→        let stdout = child.stdout.take().context("failed to capture stdout")?;
 76→        let stderr = child.stderr.take();
 77→
 78→        let pending: Arc<Mutex<HashMap<String, oneshot::Sender<JsonRpcResponse>>>> =
 79→            Arc::new(Mutex::new(HashMap::new()));
 80→
 81→        let transport = Arc::new(Self {
 82→            child: Mutex::new(child),
 83→            stdin: Mutex::new(stdin),
 84→            pending: Arc::clone(&pending),
 85→            next_id: AtomicU64::new(1),
 86→            request_timeout,
 87→            reader_handle: Mutex::new(None),
 88→        });
 89→
 90→        // Start stderr reader task (log server errors).
 91→        if let Some(stderr) = stderr {
 92→            tokio::spawn(async move {
 93→                let mut reader = BufReader::new(stderr);
 94→                let mut line = String::new();
 95→                loop {
 96→                    line.clear();
 97→                    match reader.read_line(&mut line).await {
 98→                        Ok(0) => break,
 99→                        Ok(_) => {
100→                            let trimmed = line.trim();
101→                            if !trimmed.is_empty() {
102→                                warn!(stderr = %trimmed, "MCP server stderr");
103→                            }
104→                        },
105→                        Err(_) => break,
106→                    }
107→                }
108→            });
109→        }
110→
111→        // Start stdout reader task.
112→        let pending_clone = Arc::clone(&pending);
113→        let handle = tokio::spawn(async move {
114→            let mut reader = BufReader::new(stdout);
115→            let mut line = String::new();
116→            loop {
117→                line.clear();
118→                match reader.read_line(&mut line).await {
119→                    Ok(0) => {
120→                        debug!("MCP server stdout closed");
121→                        break;
122→                    },
123→                    Ok(_) => {
124→                        let trimmed = line.trim();
125→                        if trimmed.is_empty() {
126→                            continue;
127→                        }
128→                        debug!(raw = %trimmed, "MCP server -> client");
129→
130→                        // Try to parse as response (has id field).
131→                        match serde_json::from_str::<JsonRpcResponse>(trimmed) {
132→                            Ok(resp) => {
133→                                let key = resp.id.to_string();
134→                                let mut map = pending_clone.lock().await;
135→                                if let Some(tx) = map.remove(&key) {
136→                                    let _ = tx.send(resp);
137→                                } else {
138→                                    warn!(id = %key, "received response for unknown request id");
139→                                }
140→                            },
141→                            Err(e) => {
142→                                debug!(error = %e, line = %trimmed, "MCP server sent non-response line");
143→                            },
144→                        }
145→                    },
146→                    Err(e) => {
147→                        warn!(error = %e, "error reading from MCP server stdout");
148→                        break;
149→                    },
150→                }
151→            }
152→        });
153→
154→        *transport.reader_handle.lock().await = Some(handle);
155→        Ok(transport)
156→    }
157→}
