159→#[async_trait::async_trait]
160→impl McpTransport for StdioTransport {
161→    async fn request(
162→        &self,
163→        method: &str,
164→        params: Option<serde_json::Value>,
165→    ) -> Result<JsonRpcResponse> {
166→        let id = self.next_id.fetch_add(1, Ordering::SeqCst);
167→        let req = JsonRpcRequest::new(id, method, params);
168→        let id_key = req.id.to_string();
169→
170→        let (tx, rx) = oneshot::channel();
171→        {
172→            let mut map = self.pending.lock().await;
173→            map.insert(id_key.clone(), tx);
174→        }
175→
176→        let mut payload = serde_json::to_string(&req)?;
177→        payload.push('\n');
178→
179→        debug!(method = %method, id = %id, "client -> MCP server");
180→
181→        {
182→            let mut stdin = self.stdin.lock().await;
183→            stdin.write_all(payload.as_bytes()).await?;
184→            stdin.flush().await?;
185→        }
186→
187→        let resp = tokio::time::timeout(self.request_timeout, rx)
188→            .await
189→            .with_context(|| {
190→                format!(
191→                    "MCP request '{method}' timed out after {}s (no response from server)",
192→                    self.request_timeout.as_secs()
193→                )
194→            })?
195→            .with_context(|| {
196→                format!("MCP reader task dropped while waiting for '{method}' response")
197→            })?;
198→
199→        if let Some(ref err) = resp.error {
200→            return Err(Error::message(format!(

300→                messages.push(ChatMessage::tool(tool_call_id, content));
301→            },
302→            // notice entries are UI-only informational messages.
303→            "notice" => continue,
304→            other => {
