318→/// Events emitted during streaming LLM completion.
319→#[derive(Debug, Clone)]
320→pub enum StreamEvent {
321→    /// Text content delta.
322→    Delta(String),
323→    /// Raw provider event payload (for debugging API responses).
324→    ProviderRaw(serde_json::Value),
325→    /// Reasoning/planning text delta (not user-visible final answer text).
326→    ReasoningDelta(String),
327→    /// A tool call has started (content_block_start with tool_use).
328→    ToolCallStart {
329→        /// Tool call ID from the provider.
330→        id: String,
331→        /// Tool name being called.
332→        name: String,
333→        /// Index of this tool call in the response (0-based).
334→        index: usize,
335→    },
336→    /// Streaming delta for tool call arguments (JSON fragment).
337→    ToolCallArgumentsDelta {
338→        /// Index of the tool call this delta belongs to.
339→        index: usize,
340→        /// JSON fragment to append to the arguments.
341→        delta: String,
342→    },
343→    /// A tool call's arguments are complete.
344→    ToolCallComplete {
345→        /// Index of the completed tool call.
346→        index: usize,
347→    },
348→    /// Stream completed successfully.
349→    Done(Usage),
350→    /// An error occurred.
351→    Error(String),
352→}
