500→/// Detect an explicit shell command in the latest user turn.
501→///
502→/// Only `/sh ...` commands are treated as explicit shell execution requests.
503→/// This keeps normal chat turns (`hey`, `hello`, etc.) out of the forced-exec path.
504→///
505→/// Supported forms:
506→/// - `/sh pwd`
507→/// - `/sh@mybot uname -a`
508→fn explicit_shell_command_from_user_content(user_content: &UserContent) -> Option<String> {
509→    let text = match user_content {
510→        UserContent::Text(text) => text.trim(),
511→        UserContent::Multimodal(_) => return None,
512→    };
513→
514→    if text.is_empty() || text.len() > 4096 || text.contains('\n') || text.contains('\r') {
515→        return None;
516→    }
517→
518→    let rest = text.strip_prefix('/')?;
519→    let split_idx = rest.find(char::is_whitespace)?;
520→    let head = &rest[..split_idx];
521→    let command = rest[split_idx..].trim_start();
522→    if command.is_empty() {
523→        return None;
524→    }
525→
526→    let head_lower = head.to_ascii_lowercase();
527→    let is_sh_prefix = if head_lower == "sh" {
528→        true
529→    } else {
530→        head_lower
531→            .strip_prefix("sh@")
532→            .is_some_and(|mention| !mention.is_empty())
533→    };
534→
535→    if !is_sh_prefix {
536→        return None;
537→    }
538→
539→    Some(command.to_string())
540→}
