544→/// Tag that starts a base64 data URI.
545→const BASE64_TAG: &str = "data:";
546→/// Marker between MIME type and base64 payload.
547→const BASE64_MARKER: &str = ";base64,";
548→/// Minimum length of a blob payload (base64 or hex) to be worth stripping.
549→const BLOB_MIN_LEN: usize = 200;
550→
551→fn is_base64_byte(b: u8) -> bool {
552→    b.is_ascii_alphanumeric() || b == b'+' || b == b'/' || b == b'='
553→}
554→
555→/// Strip base64 data-URI blobs (e.g. `data:image/png;base64,AAAA...`) and
556→/// replace them with a short placeholder. Only targets payloads ≥ 200 chars.
557→fn strip_base64_blobs(input: &str) -> String {
558→    let mut result = String::with_capacity(input.len());
559→    let mut rest = input;
560→
561→    while let Some(start) = rest.find(BASE64_TAG) {
562→        result.push_str(&rest[..start]);
563→        let after_tag = &rest[start + BASE64_TAG.len()..];
564→
565→        if let Some(marker_pos) = after_tag.find(BASE64_MARKER) {
566→            let mime_part = &after_tag[..marker_pos];
567→            let payload_start = marker_pos + BASE64_MARKER.len();
568→            let payload = &after_tag[payload_start..];
569→            let payload_len = payload.bytes().take_while(|b| is_base64_byte(*b)).count();
570→
571→            if payload_len >= BLOB_MIN_LEN {
572→                let total_uri_len = BASE64_TAG.len() + payload_start + payload_len;
573→                // Provide a descriptive message based on MIME type
574→                if mime_part.starts_with("image/") {
575→                    result.push_str("[screenshot captured and displayed in UI]");
576→                } else {
577→                    let _ = write!(result, "[{mime_part} data removed — {total_uri_len} bytes]");
578→                }
579→                rest = &rest[start + total_uri_len..];
580→                continue;
581→            }
582→        }
583→
584→        result.push_str(BASE64_TAG);
585→        rest = after_tag;
586→    }
587→    result.push_str(rest);
588→    result
589→}
