1566→        let full = normalize_model_key(&model.id);
1567→        if let Some(rank) = order.get(&full) {
1568→            return *rank;
1569→        }
1570→        let raw = normalize_model_key(raw_model_id(&model.id));
1571→        if let Some(rank) = order.get(&raw) {
1572→            return *rank;
1573→        }
1574→        let display = normalize_model_key(&model.display_name);
1575→        if let Some(rank) = order.get(&display) {
1576→            return *rank;
1577→        }
1578→        usize::MAX
1579→    }
