1581→    fn prioritize_models<'a>(
1582→        order: &HashMap<String, usize>,
1583→        models: impl Iterator<Item = &'a moltis_providers::ModelInfo>,
1584→    ) -> Vec<&'a moltis_providers::ModelInfo> {
1585→        let mut ordered: Vec<(usize, &'a moltis_providers::ModelInfo)> =
1586→            models.enumerate().collect();
1587→        ordered.sort_by(|(idx_a, a), (idx_b, b)| {
1588→            let rank_a = Self::priority_rank(order, a);
1589→            let rank_b = Self::priority_rank(order, b);
1590→            // Preferred (rank != MAX) first, then non-preferred
1591→            let bucket_a = if rank_a == usize::MAX {
1592→                1u8
1593→            } else {
1594→                0
1595→            };
1596→            let bucket_b = if rank_b == usize::MAX {
1597→                1u8
1598→            } else {
1599→                0
1600→            };
1601→            bucket_a
1602→                .cmp(&bucket_b)
1603→                .then_with(|| {
1604→                    if bucket_a == 0 {
1605→                        rank_a.cmp(&rank_b)
1606→                    } else {
1607→                        Ordering::Equal
1608→                    }
1609→                })
1610→                .then_with(|| {
1611→                    a.display_name
1612→                        .to_lowercase()
1613→                        .cmp(&b.display_name.to_lowercase())
1614→                })
1615→                .then_with(|| {
1616→                    subscription_provider_rank(&a.provider)
1617→                        .cmp(&subscription_provider_rank(&b.provider))
1618→                })
1619→                .then_with(|| idx_a.cmp(idx_b))
1620→        });
1621→        ordered.into_iter().map(|(_, model)| model).collect()
1622→    }
