1662→fn levenshtein_distance(a: &str, b: &str) -> usize {
1663→    if a.is_empty() {
1664→        return b.chars().count();
1665→    }
1666→    if b.is_empty() {
1667→        return a.chars().count();
1668→    }
1669→
1670→    let b_chars: Vec<char> = b.chars().collect();
1671→    let a_chars: Vec<char> = a.chars().collect();
1672→    let mut prev: Vec<usize> = (0..=b_chars.len()).collect();
1673→    let mut curr = vec![0; b_chars.len() + 1];
1674→
1675→    for (i, a_ch) in a_chars.iter().enumerate() {
1676→        curr[0] = i + 1;
1677→        for (j, b_ch) in b_chars.iter().enumerate() {
1678→            let cost = usize::from(a_ch != b_ch);
1679→            let deletion = prev[j + 1] + 1;
1680→            let insertion = curr[j] + 1;
1681→            let substitution = prev[j] + cost;
1682→            curr[j + 1] = deletion.min(insertion).min(substitution);
1683→        }
1684→        std::mem::swap(&mut prev, &mut curr);
1685→    }
1686→
1687→    prev[b_chars.len()]
1688→}
