2634→            None
2635→        };
2636→
2637→        let Some(target_run_id) = resolved_run_id.clone() else {
2638→            return (None, false);
2639→        };
2640→
2641→        if terminal_runs.read().await.contains(&target_run_id) {
2642→            return (resolved_run_id, false);
2643→        }
2644→
2645→        let aborted = if let Some(handle) = active_runs.write().await.remove(&target_run_id) {
2646→            handle.abort();
2647→            true
2648→        } else {
2649→            false
2650→        };
2651→
2652→        let mut by_session = active_runs_by_session.write().await;
2653→        if let Some(key) = session_key
