    pub async fn remove(&self, key: &str) -> Option<SessionEntry> {
        let entry = self.get(key).await;
        sqlx::query("DELETE FROM sessions WHERE key = ?")
            .bind(key)
            .execute(&self.pool)
            .await
            .ok();
        if entry.is_some() {
            self.emit(crate::session_events::SessionEvent::Deleted {
                session_key: key.to_string(),
            });
        }
        entry
    }

