                    std::future::pending::<()>().await;
                } else {
                    yield StreamEvent::Delta("Continued answer".to_string());
                    yield StreamEvent::Done(moltis_agents::model::Usage {
                        input_tokens: 8,
                        output_tokens: 4,
                        ..Default::default()
                    });
                }
            })
        }
    }

